import{_ as o,o as t,c as l,a0 as a}from"./chunks/framework.jwovEGr5.js";const i="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR4nGMAAQAABQABDQottAAAAABJRU5ErkJggg==",s="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR4nGMAAQAABQABDQottAAAAABJRU5ErkJggg==",g=JSON.parse('{"title":"Create & Edit Custom Roles","description":"","frontmatter":{},"headers":[],"relativePath":"admin/manage-roles.md","filePath":"admin/manage-roles.md"}'),r={name:"admin/manage-roles.md"};function n(c,e,h,d,m,p){return t(),l("div",null,[...e[0]||(e[0]=[a('<h1 id="create-edit-custom-roles" tabindex="-1">Create &amp; Edit Custom Roles <a class="header-anchor" href="#create-edit-custom-roles" aria-label="Permalink to &quot;Create &amp; Edit Custom Roles&quot;">​</a></h1><p>This guide is for <code>Supreme Admin</code> users only.</p><p>The <strong>Roles</strong> area is where you review the five built-in system roles, create new custom roles, clone an existing role, and edit a role&#39;s permission matrix.</p><p><img src="'+i+'" alt="Roles list and role detail"><img src="'+s+'" alt="Permission catalog"></p><h2 id="what-this-area-is-for" tabindex="-1">What this area is for <a class="header-anchor" href="#what-this-area-is-for" aria-label="Permalink to &quot;What this area is for&quot;">​</a></h2><p>Use the Roles area when you need to:</p><ul><li>review the built-in roles</li><li>create a custom role</li><li>clone an existing role as a starting point</li><li>change a role&#39;s permission matrix</li><li>reset system roles back to their defaults</li><li>delete a custom role that is no longer needed</li></ul><h2 id="system-roles-vs-custom-roles" tabindex="-1">System roles vs custom roles <a class="header-anchor" href="#system-roles-vs-custom-roles" aria-label="Permalink to &quot;System roles vs custom roles&quot;">​</a></h2><p>The app has five built-in system roles:</p><ul><li><code>Supreme Admin</code></li><li><code>King</code></li><li><code>Alliance Leader</code></li><li><code>Co-Leader</code></li><li><code>Alliance Player</code></li></ul><p>Important rules:</p><ul><li>system roles cannot be deleted</li><li>system role keys cannot be changed</li><li>resetting system roles restores their default permission set</li><li>custom roles can use any combination of permissions from the catalog</li></ul><p>If you want the full list of permission keys and what each one means, use <a href="./../reference/permission-catalog.html">Permission Reference</a>.</p><h2 id="open-the-roles-area" tabindex="-1">Open the roles area <a class="header-anchor" href="#open-the-roles-area" aria-label="Permalink to &quot;Open the roles area&quot;">​</a></h2><ol><li>Open <strong>Admin</strong>.</li><li>Select <strong>Roles</strong>.</li></ol><p>The page has two main parts:</p><ul><li>a <strong>Role List</strong></li><li>a <strong>Create Role</strong> form</li></ul><h2 id="review-the-role-list" tabindex="-1">Review the role list <a class="header-anchor" href="#review-the-role-list" aria-label="Permalink to &quot;Review the role list&quot;">​</a></h2><p>Each role row shows:</p><ul><li>the role label</li><li>the scope type</li><li>how many permissions it currently has</li><li>how many user assignments use it</li><li>whether it is enabled</li></ul><p>Select a row to open the role detail page.</p><h2 id="create-a-custom-role" tabindex="-1">Create a custom role <a class="header-anchor" href="#create-a-custom-role" aria-label="Permalink to &quot;Create a custom role&quot;">​</a></h2><p>From the <strong>Create Role</strong> form, enter:</p><ul><li>a unique role key</li><li>a label</li><li>an optional description</li><li>a scope type: <code>global</code>, <code>kingdom</code>, or <code>alliance</code></li><li>an icon</li><li>a color</li><li>a priority</li></ul><p>Then select <strong>Create role</strong>.</p><p>This only creates the role record. After that, open the role detail page and choose its permissions.</p><h2 id="edit-a-role" tabindex="-1">Edit a role <a class="header-anchor" href="#edit-a-role" aria-label="Permalink to &quot;Edit a role&quot;">​</a></h2><p>On the role detail page, you can edit:</p><ul><li>label</li><li>description</li><li>scope type</li><li>icon</li><li>color</li><li>priority</li><li>enabled status</li><li>permission checkboxes</li></ul><p>For system roles, the key is locked. For custom roles, the key can be edited.</p><h2 id="edit-the-permission-matrix" tabindex="-1">Edit the permission matrix <a class="header-anchor" href="#edit-the-permission-matrix" aria-label="Permalink to &quot;Edit the permission matrix&quot;">​</a></h2><p>The right side of the role detail page groups permissions by category. Check or clear the permissions you want, then save the role.</p><p>Use <a href="./../reference/permission-catalog.html">Permission Reference</a> while doing this so you know what each key allows.</p><h2 id="clone-a-role" tabindex="-1">Clone a role <a class="header-anchor" href="#clone-a-role" aria-label="Permalink to &quot;Clone a role&quot;">​</a></h2><p>Use the <strong>Clone Role</strong> section on the detail page when you want a copy with:</p><ul><li>the same scope type</li><li>the same icon and color</li><li>the same current permission set</li></ul><p>You only need to provide:</p><ul><li>a new role key</li><li>a new label</li></ul><p>This is the fastest way to make a variation of an existing role.</p><h2 id="reset-system-roles" tabindex="-1">Reset system roles <a class="header-anchor" href="#reset-system-roles" aria-label="Permalink to &quot;Reset system roles&quot;">​</a></h2><p>Use <strong>Reset system roles</strong> when the built-in roles need to return to their default baseline.</p><p>This is useful if someone experimented with system-role permissions and you want to restore the shipped defaults.</p><h2 id="delete-a-custom-role" tabindex="-1">Delete a custom role <a class="header-anchor" href="#delete-a-custom-role" aria-label="Permalink to &quot;Delete a custom role&quot;">​</a></h2><p>Only custom roles can be deleted.</p><p>Before deleting one:</p><ul><li>make sure it is no longer assigned to any users</li><li>make sure you do not still need it as a template for another custom role</li></ul><p>If a custom role is still assigned, the app blocks deletion until those assignments are removed or changed first.</p><h2 id="scope-still-matters-after-creation" tabindex="-1">Scope still matters after creation <a class="header-anchor" href="#scope-still-matters-after-creation" aria-label="Permalink to &quot;Scope still matters after creation&quot;">​</a></h2><p>Custom roles follow the same scoped-assignment model as built-in roles:</p><ul><li><code>global</code></li><li><code>kingdom</code></li><li><code>alliance</code></li></ul><p>Creating a role does not assign it to anyone yet. After the role exists, use <a href="./../how-to/assign-roles.html">Assign or Remove Roles</a> to place it on a user in the correct kingdom or alliance context.</p>',51)])])}const A=o(r,[["render",n]]);export{g as __pageData,A as default};
